2072: anti_adjust_stack_and_probe_stack_clash (rtx size)
2073: {
2074:   /* First ensure SIZE is Pmode.  */
2075:   if (GET_MODE (size) != VOIDmode && GET_MODE (size) != Pmode)
2076:     size = convert_to_mode (Pmode, size, 1);
2077: 
2078:   /* We can get here with a constant size on some targets.  */
2079:   rtx rounded_size, last_addr, residual;
2080:   HOST_WIDE_INT probe_interval, probe_range;
2081:   bool target_probe_range_p = false;
2082:   compute_stack_clash_protection_loop_data (&rounded_size, &last_addr,
2083: 					    &residual, &probe_interval, size);
2084: 
2085:   /* Get the back-end specific probe ranges.  */
2086:   probe_range = targetm.stack_clash_protection_alloca_probe_range ();
2087:   target_probe_range_p = probe_range != 0;
2088:   gcc_assert (probe_range >= 0);
2089: 
2090:   /* If no back-end specific range defined, default to the top of the newly
2091:      allocated range.  */
2092:   if (probe_range == 0)
2093:     probe_range = probe_interval - GET_MODE_SIZE (word_mode);
2094: 
2095:   if (rounded_size != CONST0_RTX (Pmode))
2096:     {
2097:       if (CONST_INT_P (rounded_size)
2098: 	  && INTVAL (rounded_size) <= 4 * probe_interval)
2099: 	{
2100: 	  for (HOST_WIDE_INT i = 0;
2101: 	       i < INTVAL (rounded_size);
2102: 	       i += probe_interval)
2103: 	    {
2104: 	      anti_adjust_stack (GEN_INT (probe_interval));
2105: 	      /* The prologue does not probe residuals.  Thus the offset
2106: 		 here to probe just beyond what the prologue had already
2107: 		 allocated.  */
2108: 	      emit_stack_probe (plus_constant (Pmode, stack_pointer_rtx,
2109: 					       probe_range));
2110: 
2111: 	      emit_insn (gen_blockage ());
2112: 	    }
2113: 	}
2114:       else
2115: 	{
2116: 	  rtx loop_lab, end_loop;
2117: 	  bool rotate_loop = CONST_INT_P (rounded_size);
2118: 	  emit_stack_clash_protection_probe_loop_start (&loop_lab, &end_loop,
2119: 							last_addr, rotate_loop);
2120: 
2121: 	  anti_adjust_stack (GEN_INT (probe_interval));
2122: 
2123: 	  /* The prologue does not probe residuals.  Thus the offset here
2124: 	     to probe just beyond what the prologue had already
2125: 	     allocated.  */
2126: 	  emit_stack_probe (plus_constant (Pmode, stack_pointer_rtx,
2127: 					   probe_range));
2128: 
2129: 	  emit_stack_clash_protection_probe_loop_end (loop_lab, end_loop,
2130: 						      last_addr, rotate_loop);
2131: 	  emit_insn (gen_blockage ());
2132: 	}
2133:     }
2134: 
2135:   if (residual != CONST0_RTX (Pmode))
2136:     {
2137:       rtx label = NULL_RTX;
2138:       /* RESIDUAL could be zero at runtime and in that case *sp could
2139: 	 hold live data.  Furthermore, we do not want to probe into the
2140: 	 red zone.
2141: 
2142: 	 If TARGET_PROBE_RANGE_P then the target has promised it's safe to
2143: 	 probe at offset 0.  In which case we no longer have to check for
2144: 	 RESIDUAL == 0.  However we still need to probe at the right offset
2145: 	 when RESIDUAL > PROBE_RANGE, in which case we probe at PROBE_RANGE.
2146: 
2147: 	 If !TARGET_PROBE_RANGE_P then go ahead and just guard the probe at *sp
2148: 	 on RESIDUAL != 0 at runtime if RESIDUAL is not a compile time constant.
2149: 	 */
2150:       anti_adjust_stack (residual);
