2201: anti_adjust_stack_and_probe (rtx size, bool adjust_back)
2202: {
2203:   /* We skip the probe for the first interval + a small dope of 4 words and
2204:      probe that many bytes past the specified size to maintain a protection
2205:      area at the botton of the stack.  */
2206:   const int dope = 4 * UNITS_PER_WORD;
2207: 
2208:   /* First ensure SIZE is Pmode.  */
2209:   if (GET_MODE (size) != VOIDmode && GET_MODE (size) != Pmode)
2210:     size = convert_to_mode (Pmode, size, 1);
2211: 
2212:   /* If we have a constant small number of probes to generate, that's the
2213:      easy case.  */
2214:   if (CONST_INT_P (size) && INTVAL (size) < 7 * PROBE_INTERVAL)
2215:     {
2216:       HOST_WIDE_INT isize = INTVAL (size), i;
2217:       bool first_probe = true;
2218: 
2219:       /* Adjust SP and probe at PROBE_INTERVAL + N * PROBE_INTERVAL for
2220: 	 values of N from 1 until it exceeds SIZE.  If only one probe is
2221: 	 needed, this will not generate any code.  Then adjust and probe
2222: 	 to PROBE_INTERVAL + SIZE.  */
2223:       for (i = PROBE_INTERVAL; i < isize; i += PROBE_INTERVAL)
2224: 	{
2225: 	  if (first_probe)
2226: 	    {
2227: 	      anti_adjust_stack (GEN_INT (2 * PROBE_INTERVAL + dope));
2228: 	      first_probe = false;
2229: 	    }
2230: 	  else
2231: 	    anti_adjust_stack (GEN_INT (PROBE_INTERVAL));
2232: 	  emit_stack_probe (stack_pointer_rtx);
2233: 	}
2234: 
2235:       if (first_probe)
2236: 	anti_adjust_stack (plus_constant (Pmode, size, PROBE_INTERVAL + dope));
2237:       else
2238: 	anti_adjust_stack (plus_constant (Pmode, size, PROBE_INTERVAL - i));
2239:       emit_stack_probe (stack_pointer_rtx);
2240:     }
